const spa_id = String($input.first().json.body?.spa_id || $input.first().json.spa_id || '');
if (!spa_id) throw new Error('spa_id obrigatório');
const token = $env.B24_TOKEN;
return [{ json:{
  spa_id,
  _url: 'https://promobrindes.bitrix24.com.br/rest/1/'+token+'/crm.item.get?entityTypeId=1690&id='+spa_id
} }];

const item = $('📋 GET SPA').first().json?.result?.item || {};
const d    = $('🔗 Get SPA').first().json;
const qid  = item['ufCrm276_1758655595'];
const sc   = item['ufCrm276_1758654848'];
const se   = item['ufCrm276_1758654830'];
if (!qid) throw new Error('Execute F01 primeiro — quotationId não encontrado no SPA '+d.spa_id);
if (!sc || !se) throw new Error('stopIds não encontrados no SPA '+d.spa_id);
const nome_dest  = item['ufCrm276_1758913742']  || '';
const tel_dest   = item['ufCrm276_1758913684']   || '';
const referencia = item['ufCrm276_1758913748'] || '';
const payload = {
  quotationId: qid,
  stops: [
    { stopId: sc },
    { stopId: se,
       recipient: { name: nome_dest, phone: { displayNumber: tel_dest, countryCode: '+55' } },
       remarks: referencia }
  ],
  isPODEnabled: true,
  driverNote: referencia || '',
};
return [{ json:{
  spa_id: d.spa_id,
  category_id: item.categoryId || 730,
  http_method: 'POST', http_path: '/v3/orders',
  http_body: JSON.stringify(payload)
} }];

const crypto = require('crypto');
const ts  = Date.now().toString();
const method  = $json.http_method || 'POST';
const path    = $json.http_path;
const bodyStr = $json.http_body || '';
const raw = ts + '\r\n' + method + '\r\n' + path + '\r\n\r\n' + bodyStr;
const sig = crypto.createHmac('sha256', 'sk_prod_v30Ci06vXqPeizCg6e461VZEymmFzMDAXZQwTm3NdYcwyLaS8nxrQEX0JKcp0mAM').update(raw).digest('hex');
return [{ json: { ...$json,
  _auth: 'hmac pk_prod_d38621223012b9ec71d0634589126e3b:' + ts + ':' + sig,
  _ts: ts
}}];

const o = $('🚀 POST Order').first().json;
const d = $('📐 Build Order').first().json;
if (!o.orderId) throw new Error('Sem orderId: '+JSON.stringify(o).slice(0,200));
return [{ json:{
  spa_id:      d.spa_id,
  category_id: d.category_id,
  orderId:     o.orderId,
  shareLink:   o.shareLink || '',
  status:      o.status || 'MATCHING',
  b24_fields: {
    'ufCrm276_1758817942': o.orderId,
    stageId: 'DT1690_'+d.category_id+':IN_PROCESS',
  },
} }];

const d = $input.first().json;
const token = $env.B24_TOKEN;
const url   = 'https://promobrindes.bitrix24.com.br/rest/1/'+token+'/crm.item.update';
const body  = {entityTypeId:1690,id:parseInt(d.spa_id),fields:d.b24_fields};
return [{ json:{ _url:url, _body:JSON.stringify(body), orderId:d.orderId } }];
